n":"My brother lives in Madrid.","mnemonic_en":null},{"spanish_text":"Hermana","english_text":"Sister","section_name":"English Basics","part_of_speech":"noun","definition_en":"A female sibling.","main_translations_es":["hermana","hermana mayor","hermana menor"],"collocations":["big sister","little sister","sister city","sister company"],"example_sentence":"My sister lives in Madrid.","example_es":"Mi hermana vive en Madrid.","example_en":"My sister lives in Madrid.","mnemonic_en":null},{"spanish_text":"Hijo","english_text":"Son","section_name":"English Basics","part_of_speech":"noun","definition_en":"A male child or offspring.","main_translations_es":["hijo","varón","crío"],"collocations":["son of a gun","son of the president","son of the soil"],"example_sentence":"My son is studying medicine at university.","example_es":"Mi hijo está estudiando medicina en la universidad.","example_en":"My son is studying medicine at university.","mnemonic_en":null},{"spanish_text":"Hija","english_text":"Daughter","section_name":"English Basics","part_of_speech":"noun","definition_en":"A female child in relation to her parents.","main_translations_es":["hija","descendiente femenina"],"collocations":["my daughter","elder daughter","only daughter","stepdaughter"],"example_sentence":"My daughter is studying medicine at the university.","example_es":"Mi hija está estudiando medicina en la universidad.","example_en":"My daughter is studying medicine at the university.","mnemonic_en":null},{"spanish_text":"Amigo","english_text":"Friend","section_name":"English Basics","part_of_speech":"noun","definition_en":"A person with whom one shares a bond of mutual affection and trust.","main_translations_es":["Camarada","Compañero","Colega"],"collocations":["close friend","best friend","friendship","friend in need"],"example_sentence":"My friend helped me move on Saturday.","example_es":"Mi amigo me ayudó a mudarme el sábado.","example_en":"My friend helped me move on Saturday.","mnemonic_en":null},{"spanish_text":"Familia","english_text":"Family","section_name":"English Basics","part_of_speech":"noun","definition_en":"A group of related individuals, such as parents and their children, or people connected by blood, marriage, or adoption.","main_translations_es":["Familia","Parentesco","Hogar"],"collocations":["family tree","family reunion","family member","family ties"],"example_sentence":"My family gets together every Sunday for dinner.","example_es":"Mi familia se reúne cada domingo para cenar juntos.","example_en":"My family gets together every Sunday for dinner.","mnemonic_en":null},{"spanish_text":"Bebé","english_text":"Baby","section_name":"English Basics","part_of_speech":"noun","definition_en":"A very young child or infant.","main_translations_es":["bebé","infante","niño pequeño"],"collocations":["baby shower","baby steps","baby boom","cry like a baby"],"example_sentence":"The baby is sleeping in its crib.","example_es":"El bebé está durmiendo en su cuna.","example_en":"The baby is sleeping in its crib.","mnemonic_en":null},{"spanish_text":"Niño","english_text":"Child","section_name":"English Basics","part_of_speech":"noun","definition_en":"A young human being.","main_translations_es":["chico","infante","menor"],"collocations":["child care","child development","child support","child prodigy"],"example_sentence":"The child plays in the park.","example_es":"El niño juega en el parque.","example_en":"The child plays in the park.","mnemonic_en":null},{"spanish_text":"Cabeza","english_text":"Head","section_name":"English Basics","part_of_speech":"noun","definition_en":"the upper part of the human body that contains the brain, eyes, ears, nose, and mouth","main_translations_es":["cabeza","coco","cráneo"],"collocations":["head over heels","head start","head of the class","head and shoulders"],"example_sentence":"My head hurts.","example_es":"Me duele la cabeza.","example_en":"My head hurts.","mnemonic_en":null},{"spanish_text":"Ojo","english_text":"Eye","section_name":"English Basics","part_of_speech":"noun","definition_en":"The organ of sight in humans and many animals.","main_translations_es":["mirada","vista","óculo"],"collocations":["keep an eye on","in the blink of an eye","the apple of my eye","eye contact"],"example_sentence":"My eye hurts.","example_es":"Me duele el ojo.","example_en":"My eye hurts.","mnemonic_en":null},{"spanish_text":"Nariz","english_text":"Nose","section_name":"English Basics","part_of_speech":"noun","definition_en":"The protruding organ on the face used for smelling and breathing.","main_translations_es":["Nariz","Hocico","Pico"],"collocations":["runny nose","nose job","keep your nose out","nose to the grindstone"],"example_sentence":"My nose hurts when I breathe cold air.","example_es":"Me duele la nariz cuando respiro aire frío.","example_en":"My nose hurts when I breathe cold air.","mnemonic_en":null},{"spanish_text":"Boca","english_text":"Mouth","section_name":"English Basics","part_of_speech":"noun","definition_en":"The opening in the face through which a person eats, speaks, and breathes.","main_translations_es":["boca","hocico"],"collocations":["mouth water","mouth of the river","mouth guard","mouthful"],"example_sentence":"My mouth hurts after eating ice cream.","example_es":"Me duele la boca después de comer helado.","example_en":"My mouth hurts after eating ice cream.","mnemonic_en":null},{"spanish_text":"Mano","english_text":"Hand","section_name":"English Basics","part_of_speech":"noun","definition_en":"The five‑fingered, prehensile extremity at the end of a human arm used for grasping and manipulating objects.","main_translations_es":["mano","palma","manita"],"collocations":["hand in hand","hand over","hand out"],"example_sentence":"My hand hurts after hitting the table.","example_es":"Me duele la mano después de golpear la mesa.","example_en":"My hand hurts after hitting the table.","mnemonic_en":null},{"spanish_text":"Brazo","english_text":"Arm","section_name":"English Basics","part_of_speech":"noun","definition_en":"The upper limb of the human body extending from the shoulder to the hand.","main_translations_es":["brazo","miembro superior"],"collocations":["arm of a chair","arm around","arm wrestling","arm strength"],"example_sentence":"My arm hurts after lifting weights.","example_es":"Me duele el brazo después de levantar pesas.","example_en":"My arm hurts after lifting weights.","mnemonic_en":null},{"spanish_text":"Pierna","english_text":"Leg","section_name":"English Basics","part_of_speech":"noun","definition_en":"A limb of the human body used for standing and walking, extending from the hip to the foot.","main_translations_es":["Pierna","Extremidad inferior","Miembro inferior"],"collocations":["leg of a table","leg day","leg injury","leg room"],"example_sentence":"My leg hurts after running.","example_es":"Me duele la pierna después de correr.","example_en":"My leg hurts after running.","mnemonic_en":null},{"spanish_text":"Pie","english_text":"Foot","section_name":"English Basics","part_of_speech":"noun","definition_en":"The lower extremity of the leg on which a person stands and walks.","main_translations_es":["pie","extremidad inferior","parte inferior del cuerpo"],"collocations":["foot of the mountain","foot the bill","foot traffic","foot in the door"],"example_sentence":"My foot hurts after running.","example_es":"Me duele el pie después de correr.","example_en":"My foot hurts after running.","mnemonic_en":null},{"spanish_text":"Espalda","english_text":"Back","section_name":"English Basics","part_of_speech":"noun","definition_en":"The rear surface of a person or object, opposite the front.","main_translations_es":["dorso","parte posterior","espalda"],"collocations":["back up","back down","back and forth","back to basics"],"example_sentence":"My back hurts after running.","example_es":"Me duele la espalda después de correr.","example_en":"My back hurts after running.","mnemonic_en":null},{"spanish_text":"Cara","english_text":"Face","section_name":"English Basics","part_of_speech":"noun","definition_en":"The front part of a person''s head that includes the eyes, nose, and mouth.","main_translations_es":["rostro","faz","semblante"],"collocations":["face value","face the music","in your face","face-to-face"],"example_sentence":"She has a very friendly face.","example_es":"Ella tiene una cara muy amable.","example_en":"She has a very friendly face.","mnemonic_en":null},{"spanish_text":"Pelo","english_text":"Hair","section_name":"English Basics","part_of_speech":"noun","definition_en":"Hair is the thin strands that grow from the skin of humans and animals, especially on the head.","main_translations_es":["Cabello","Cabellera"],"collocations":["hair cut","hair color","hair style","hair loss"],"example_sentence":"I cut my hair yesterday.","example_es":"Me corté el pelo ayer.","example_en":"I cut my hair yesterday.","mnemonic_en":null},{"spanish_text":"Oreja","english_text":"Ear","section_name":"English Basics","part_of_speech":"noun","definition_en":"The organ of hearing located on each side of the head.","main_translations_es":["oreja","oído","lóbulo"],"collocations":["lend an ear","in one ear and out the other","ear to the ground"],"example_sentence":"My right ear hurts.","example_es":"Me duele la oreja derecha.","example_en":"My right ear hurts.","mnemonic_en":null},{"spanish_text":"Agua","english_text":"Water","section_name":"English Basics","part_of_speech":"noun","definition_en":"A clear, colorless, odorless, and tasteless liquid that makes up seas, lakes, rivers, and rain, and is essential for most life.","main_translations_es":["agua","el agua","el líquido"],"collocations":["bottled water","running water","water supply","water bottle"],"example_sentence":"I need to drink water.","example_es":"Necesito beber agua.","example_en":"I need to drink water.","mnemonic_en":null},{"spanish_text":"Pan","english_text":"Bread","section_name":"English Basics","part_of_speech":"noun","definition_en":"A staple food made from flour and water, typically baked.","main_translations_es":["pan","pan de trigo","pan integral"],"collocations":["bread and butter","break bread","earn your bread","breadwinner"],"example_sentence":"I like to eat fresh bread every morning.","example_es":"Me gusta comer pan recién horneado cada mañana.","example_en":"I like to eat fresh bread every morning.","mnemonic_en":null},{"spanish_text":"Leche","english_text":"Milk","section_name":"English Basics","part_of_speech":"noun","definition_en":"Milk is the white liquid produced by the mammary glands of mammals, commonly consumed as a beverage and used in cooking.","main_translations_es":["leche","producto lácteo","leche fresca"],"collocations":["a glass of milk","milk the cow","milk chocolate","milkshake"],"example_sentence":"I like to drink milk before going to bed.","example_es":"Me gusta tomar leche antes de dormir.","example_en":"I like to drink milk before going to bed.","mnemonic_en":null},{"spanish_text":"Manzana","english_text":"Apple","section_name":"English Basics","part_of_speech":"noun","definition_en":"A round fruit with red, green, or yellow skin and a sweet, crisp flesh, typically grown on apple trees.","main_translations_es":["manzana","poma","fruta"],"collocations":["apple pie","apple of my eye","big apple","apple orchard"],"example_sentence":"I bought an apple at the market.","example_es":"Compré una manzana en el mercado.","example_en":"I bought an apple at the market.","mnemonic_en":null},{"spanish_text":"Perro","english_text":"Dog","section_name":"English Basics","part_of_speech":"noun","definition_en":"A domesticated carnivorous mammal commonly kept as a pet or used for work, known for its loyalty and barking.","main_translations_es":["can","chucho","cachorro"],"collocations":["dog house","dog days","dog bark","dog tag"],"example_sentence":"The dog runs in the park.","example_es":"El perro corre en el parque.","example_en":"The dog runs in the park.","mnemonic_en":null},{"spanish_text":"Gato","english_text":"Cat","section_name":"English Basics","part_of_speech":"noun","definition_en":"A small domesticated carnivorous mammal with soft fur, often kept as a pet.","main_translations_es":["gato","felino doméstico","minino"],"collocations":["cat nap","scaredy cat","fat cat","cat''s meow"],"example_sentence":"The cat sleeps on the sofa.","example_es":"El gato duerme en el sofá.","example_en":"The cat sleeps on the sofa.","mnemonic_en":null},{"spanish_text":"Libro","english_text":"Book","section_name":"English Basics","part_of_speech":"noun","definition_en":"A bound collection of written or printed pages that can be read.","main_translations_es":["libro","tomo","volumen"],"collocations":["read a book","book a ticket","book club","book of poems"],"example_sentence":"I am reading an interesting book.","example_es":"Estoy leyendo un libro interesante.","example_en":"I am reading an interesting book.","mnemonic_en":null},{"spanish_text":"Escuela","english_text":"School","section_name":"English Basics","part_of_speech":"noun","definition_en":"An institution where children and young adults receive education.","main_translations_es":["Colegio","Instituto","Academia"],"collocations":["go to school","school bus","school year","school of thought"],"example_sentence":"The school is closed today.","example_es":"La escuela está cerrada hoy.","example_en":"The school is closed today.","mnemonic_en":null},{"spanish_text":"Profesor","english_text":"Teacher","section_name":"English Basics","part_of_speech":"noun","definition_en":"A person who teaches, especially in a school.","main_translations_es":["Maestro","Docente","Catedrático"],"collocations":["high school teacher","teacher training","teacher''s lounge","teacher''s pet"],"example_sentence":"The teacher explained the lesson clearly.","example_es":"El profesor explicó la lección con claridad.","example_en":"The teacher explained the lesson clearly.","mnemonic_en":null},{"spanish_text":"Estudiante","english_text":"Student","section_name":"English Basics","part_of_speech":"noun","definition_en":"A person who is enrolled in an educational institution or is studying.","main_translations_es":["Estudiante","Alumno","Alumna"],"collocations":["full-time student","graduate student","student loan","student visa"],"example_sentence":"The student studies for the exam.","example_es":"El estudiante estudia para el examen.","example_en":"The student studies for the exam.","mnemonic_en":null},{"spanish_text":"Abrir","english_text":"Open","section_name":"English Basics","part_of_speech":"verb","definition_en":"To cause something to become not closed or to allow access.","main_translations_es":["Abrir","Desplegar","Destapar"],"collocations":["open the door","open a file","open a window","open up"],"example_sentence":"I am going to open the window.","example_es":"Voy a abrir la ventana.","example_en":"I am going to open the window.","mnemonic_en":null},{"spanish_text":"Cerrar","english_text":"Close","section_name":"English Basics","part_of_speech":"verb","definition_en":"To shut something so that it is no longer open.","main_translations_es":["Clausurar","Cerrar","Sellar"],"collocations":["close the door","close the deal","close a window","close the book"],"example_sentence":"Please close the door when you leave.","example_es":"Por favor, cierra la puerta cuando salgas.","example_en":"Please close the door when you leave.","mnemonic_en":null},{"spanish_text":"Leer","english_text":"Read","section_name":"English Basics","part_of_speech":"verb","definition_en":"To look at and understand the meaning of written or printed material.","main_translations_es":["descifrar","revisar","examinar"],"collocations":["read a book","read aloud","read between the lines","read the news"],"example_sentence":"I like to read before going to bed.","example_es":"Me gusta leer antes de dormir.","example_en":"I like to read before going to bed.","mnemonic_en":null},{"spanish_text":"Escribir","english_text":"Write","section_name":"English Basics","part_of_speech":"verb","definition_en":"To produce text or symbols on a surface using a pen, pencil, keyboard, or other instrument.","main_translations_es":["Redactar","Anotar","Apuntar"],"collocations":["write a letter","write down","write a report","write an essay"],"example_sentence":"I like to write letters by hand.","example_es":"Me gusta escribir cartas a mano.","example_en":"I like to write letters by hand.","mnemonic_en":null},{"spanish_text":"Escuchar","english_text":"Listen","section_name":"English Basics","part_of_speech":"verb","definition_en":"To give attention to sounds by hearing them.","main_translations_es":["Oír","Atender","Prestar atención"],"collocations":["listen carefully","listen up","listen to music","listen attentively"],"example_sentence":"I like to listen to music while I study.","example_es":"Me gusta escuchar música mientras estudio.","example_en":"I like to listen to music while I study.","mnemonic_en":null},{"spanish_text":"Hablar","english_text":"Speak","section_name":"English Basics","part_of_speech":"verb","definition_en":"To utter words or communicate verbally.","main_translations_es":["Conversar","Charlar","Platicar"],"collocations":["speak up","speak out","speak one''s mind","speak fluently"],"example_sentence":"I like to speak with my friends.","example_es":"Me gusta hablar con mis amigos.","example_en":"I like to speak with my friends.","mnemonic_en":null},{"spanish_text":"Comer","english_text":"Eat","section_name":"English Basics","part_of_speech":"verb","definition_en":"To consume food or drink.","main_translations_es":["Alimentarse","Ingerir","Deglutir"],"collocations":["eat out","eat up","eat healthy","eat like a horse"],"example_sentence":"I like to eat pizza on Fridays.","example_es":"Me gusta comer pizza los viernes.","example_en":"I like to eat pizza on Fridays.","mnemonic_en":null},{"spanish_text":"Beber","english_text":"Drink","section_name":"English Basics","part_of_speech":"verb","definition_en":"To consume a liquid.","main_translations_es":["Tomar","Beber","Ingerir"],"collocations":["drink water","drink coffee","drink responsibly","drink up"],"example_sentence":"I like to drink water after running.","example_es":"Me gusta beber agua después de correr.","example_en":"I like to drink water after running.","mnemonic_en":null},{"spanish_text":"Ir","english_text":"Go","section_name":"English Basics","part_of_speech":"verb","definition_en":"to move or travel from one place to another","main_translations_es":["Desplazarse","Acudir","Irse"],"collocations":["go ahead","go home","go for it","go on"],"example_sentence":"I go to the market every morning.","example_es":"Voy al mercado cada mañana.","example_en":"I go to the market every morning.","mnemonic_en":null},{"spanish_text":"Venir","english_text":"Come","section_name":"English Basics","part_of_speech":"verb","definition_en":"to move or travel toward a place or person","main_translations_es":["Llegar","Acudir","Arribar"],"collocations":["come in","come back","come across","come up"],"example_sentence":"Can you come to my house tomorrow?","example_es":"¿Puedes venir a mi casa mañana?","example_en":"Can you come to my house tomorrow?","mnemonic_en":null},{"spanish_text":"Ver","english_text":"See","section_name":"English Basics","part_of_speech":"verb","definition_en":"To perceive something with the eyes.","main_translations_es":["Observar","Mirar","Contemplar"],"collocations":["see the light","see a doctor","see what I mean","see the point"],"example_sentence":"Can you see the mountain from here?","example_es":"¿Puedes ver la montaña desde aquí?","example_en":"Can you see the mountain from here?","mnemonic_en":null},{"spanish_text":"Querer","english_text":"Want","section_name":"English Basics","part_of_speech":"verb","definition_en":"To desire or wish for something.","main_translations_es":["desear","tener ganas de","anhelar"],"collocations":["want to","I want","want something","want for"],"example_sentence":"I want to travel to Spain this summer.","example_es":"Quiero viajar a España este verano.","example_en":"I want to travel to Spain this summer.","mnemonic_en":null},{"spanish_text":"Necesitar","english_text":"Need","section_name":"English Basics","part_of_speech":"verb","definition_en":"To require something because it is necessary or desirable.","main_translations_es":["precisar","requerir","tener que"],"collocations":["need to","in need of","need help","need a break"],"example_sentence":"I need to buy milk.","example_es":"Necesito comprar leche.","example_en":"I need to buy milk.","mnemonic_en":null},{"spanish_text":"Grande","english_text":"Big","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Having a large size, extent, or magnitude.","main_translations_es":["Enorme","Gigante","Amplio"],"collocations":["big deal","big picture","big time","big brother"],"example_sentence":"The dog is very big.","example_es":"El perro es muy grande.","example_en":"The dog is very big.","mnemonic_en":null},{"spanish_text":"Pequeño","english_text":"Small","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Having a limited size, amount, or extent.","main_translations_es":["chico","pequeñito","menudo"],"collocations":["small business","small town","small amount","small problem"],"example_sentence":"The dog is small but very brave.","example_es":"El perro es pequeño pero muy valiente.","example_en":"The dog is small but very brave.","mnemonic_en":null},{"spanish_text":"Nuevo","english_text":"New","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Recently created, discovered, or introduced; not existing before.","main_translations_es":["Reciente","Fresco","Novedoso"],"collocations":["brand new","new and improved","new generation","new era"],"example_sentence":"I bought a new car.","example_es":"Compré un coche nuevo.","example_en":"I bought a new car.","mnemonic_en":null},{"spanish_text":"Viejo","english_text":"Old","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Having existed or been in use for a long time; not new.","main_translations_es":["antiguo","anciano","vetusto"],"collocations":["old friend","old habits","old age","old-fashioned"],"example_sentence":"The old book is on the shelf.","example_es":"El libro viejo está en la estantería.","example_en":"The old book is on the shelf.","mnemonic_en":null},{"spanish_text":"Feliz","english_text":"Happy","section_name":"English Basics","part_of_speech":"adjective","definition_en":"Feeling or showing pleasure, contentment, or joy.","main_translations_es":["Contento","Alegre","Jubiloso"],"collocations":["happy birthday","happy hour","happy ending","happy couple"],"example_sentence":"I am happy with the results.","example_es":"Estoy feliz con los resultados.","example_en":"I am happy with the results.","mnemonic_en":null}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text
)
where not exists (
  select 1 from public.cards c2
  where c2.deck_id = dk.id
    and lower(c2.spanish_text) = lower(x.spanish_text)
    and lower(c2.english_text) = lower(x.english_text)
);

-- daily-life (107 cards)
insert into public.decks (slug, title, description, language_from, language_to)
values ('daily-life', 'Daily Life', 'Useful vocabulary for routines, places, and simple actions.', 'es', 'en')
on conflict (slug) do nothing;

insert into public.cards (deck_id, spanish_text, english_text, is_enabled, generation_phase, generation_metadata, section_name, part_of_speech, definition_en, main_translations_es, collocations, example_sentence, example_es, example_en, mnemonic_en)
select dk.id, x.spanish_text, x.english_text, true, 'refined', '{}'::jsonb, x.section_name, x.part_of_speech, x.definition_en,
       coalesce(x.main_translations_es, '[]'::jsonb), coalesce(x.collocations, '[]'::jsonb), x.example_sentence, x.example_es, x.example_en, x.mnemonic_en
from (select id from public.decks where slug = 'daily-life') dk
