le_sentence":"Send a message to your friend when you arrive.","example_es":"Envía un mensaje a tu amigo cuando llegues.","example_en":"Send a message to your friend when you arrive.","mnemonic_en":null},{"spanish_text":"Revisa el correo","english_text":"Check the mail","section_name":"Daily Life","part_of_speech":"verb phrase","definition_en":"To look at or retrieve the email messages.","main_translations_es":["Revisa el correo","Chequea el correo","Mira el correo"],"collocations":["check the mail regularly","check the mail before leaving","check the mail daily"],"example_sentence":"Check the mail before you leave.","example_es":"Revisa el correo antes de salir.","example_en":"Check the mail before you leave.","mnemonic_en":null},{"spanish_text":"Necesito descansar","english_text":"I need to rest","section_name":"Daily Life","part_of_speech":"expression","definition_en":"A statement indicating that the speaker requires rest.","main_translations_es":["Tengo que descansar","Me hace falta descansar","Preciso descansar"],"collocations":["I need to rest and recover","I need to rest for a while","I need to rest after work"],"example_sentence":"I need to rest after so much work.","example_es":"Necesito descansar después de tanto trabajo.","example_en":"I need to rest after so much work.","mnemonic_en":null},{"spanish_text":"Tengo prisa","english_text":"I am in a hurry","section_name":"Daily Life","part_of_speech":"expression","definition_en":"A statement indicating that someone needs to act quickly because they have limited time.","main_translations_es":["Voy deprisa","Estoy apurado","Tengo urgencia"],"collocations":["I''m in a hurry","in a hurry","hurry up","rush hour"],"example_sentence":"I''m in a hurry, so I can''t stay long.","example_es":"Tengo prisa, así que no puedo quedarme mucho tiempo.","example_en":"I''m in a hurry, so I can''t stay long.","mnemonic_en":null},{"spanish_text":"No pasa nada","english_text":"No problem","section_name":"Daily Life","part_of_speech":"expression","definition_en":"A casual way of saying that something is not an issue or that you are happy to help.","main_translations_es":["No hay problema","Todo bien","No ocurre nada"],"collocations":["No problem at all","No problem, thanks","No problem, you''re welcome"],"example_sentence":"No problem, we can try again.","example_es":"No pasa nada, podemos intentarlo de nuevo.","example_en":"No problem, we can try again.","mnemonic_en":null},{"spanish_text":"Vecino","english_text":"Neighbor","section_name":"Daily Life","part_of_speech":"noun","definition_en":"A person who lives near or next to another person.","main_translations_es":["Vecino","Vecina","colindante"],"collocations":["next‑door neighbor","good neighbor","friendly neighbor","neighboring house"],"example_sentence":"My neighbor helped me carry the boxes.","example_es":"Mi vecino me ayudó a cargar las cajas.","example_en":"My neighbor helped me carry the boxes.","mnemonic_en":null},{"spanish_text":"Parque","english_text":"Park","section_name":"Daily Life","part_of_speech":"noun","definition_en":"A public area of land with grass, trees, and facilities for recreation and leisure.","main_translations_es":["Parque","Jardín público","Zona verde"],"collocations":["national park","theme park","park the car"],"example_sentence":"We go to the park to play soccer.","example_es":"Vamos al parque a jugar al fútbol.","example_en":"We go to the park to play soccer.","mnemonic_en":null}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text
)
where not exists (
  select 1 from public.cards c2
  where c2.deck_id = dk.id
    and lower(c2.spanish_text) = lower(x.spanish_text)
    and lower(c2.english_text) = lower(x.english_text)
);

