ations":["customs officer","customs duty","customs clearance","customs inspection"],"example_sentence":"The package arrived at customs without any problems.","example_es":"El paquete llegó a la aduana sin problemas.","example_en":"The package arrived at customs without any problems.","mnemonic_en":null},{"spanish_text":"Control de seguridad","english_text":"Security check","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A procedure to verify safety or compliance, often involving inspection of items or people.","main_translations_es":["Verificación de seguridad","Chequeo de seguridad","Inspección de seguridad"],"collocations":["security check at the airport","security check before boarding","security check procedure","security check process"],"example_sentence":"The security check at the airport was very strict.","example_es":"El control de seguridad en el aeropuerto fue muy riguroso.","example_en":"The security check at the airport was very strict.","mnemonic_en":null},{"spanish_text":"Vuelo","english_text":"Flight","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"the act of flying through the air","main_translations_es":["Viaje aéreo","Trayecto aéreo","Aviación"],"collocations":["flight schedule","flight attendant","flight delay","flight ticket"],"example_sentence":"The flight tomorrow is delayed.","example_es":"El vuelo de mañana está retrasado.","example_en":"The flight tomorrow is delayed.","mnemonic_en":null},{"spanish_text":"Asiento","english_text":"Seat","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A piece of furniture or structure designed for sitting.","main_translations_es":["Silla","Puesto"],"collocations":["seat belt","seat of the pants","seat of the mind"],"example_sentence":"The seat on the bus was very comfortable.","example_es":"El asiento del autobús estaba muy cómodo.","example_en":"The seat on the bus was very comfortable.","mnemonic_en":null},{"spanish_text":"Ventanilla"