],"example_sentence":"The air conditioning in the hotel is very efficient.","example_es":"El aire acondicionado en el hotel es muy eficiente.","example_en":"The air conditioning in the hotel is very efficient.","mnemonic_en":null},{"spanish_text":"Wi-Fi","english_text":"Wi-Fi","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"a wireless networking technology that allows devices to connect to the internet or communicate with each other without cables.","main_translations_es":["Wi-Fi","wifi","red inalámbrica"],"collocations":["Wi-Fi connection","Wi-Fi network","Wi-Fi hotspot","Wi-Fi signal"],"example_sentence":"I connected my phone to the hotel’s Wi‑Fi.","example_es":"Conecté mi teléfono al Wi‑Fi del hotel.","example_en":"I connected my phone to the hotel’s Wi‑Fi.","mnemonic_en":null},{"spanish_text":"Ascensor","english_text":"Elevator","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A mechanical device that transports people or goods between floors of a building.","main_translations_es":["Elevador"],"collocations":["take the elevator","elevator music","elevator pitch","elevator ride"],"example_sentence":"The elevator is at the building''s entrance.","example_es":"El ascensor está en la entrada del edificio.","example_en":"The elevator is at the building''s entrance.","mnemonic_en":null},{"spanish_text":"Equipaje","english_text":"Luggage","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"Items of personal belongings carried in a suitcase or bag, especially when traveling.","main_translations_es":["Bolsas","Maletas","Equipamiento"],"collocations":["checked luggage","carry-on luggage","lost luggage","luggage tag"],"example_sentence":"My luggage from the flight arrived late.","example_es":"El equipaje de mi vuelo llegó tarde.","example_en":"My luggage from the flight arrived late.","mnemonic_en":null},{"spanish_text":"Mochila","english_text":"Backpack","section_name":"Travel Phrases","part_of_speech":