y exit"],"example_sentence":"The medical emergency requires immediate attention.","example_es":"La emergencia médica requiere atención inmediata.","example_en":"The medical emergency requires immediate attention.","mnemonic_en":null},{"spanish_text":"He perdido mi pasaporte","english_text":"I lost my passport","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement indicating that the speaker has lost their passport.","main_translations_es":["Perdí mi pasaporte","He extraviado mi pasaporte","He perdido mi documento de viaje"],"collocations":["I lost my passport at the airport","I lost my passport while traveling","I lost my passport and had to get a replacement","I lost my passport and can''t travel"],"example_sentence":"I lost my passport, so I need to apply for a new one.","example_es":"He perdido mi pasaporte, así que necesito solicitar uno nuevo.","example_en":"I lost my passport, so I need to apply for a new one.","mnemonic_en":null},{"spanish_text":"He perdido mi cartera","english_text":"I lost my wallet","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A sentence expressing that the speaker has misplaced or lost their wallet.","main_translations_es":["Perdí mi cartera","He perdido mi billetera","Perdí mi bolso"],"collocations":["I lost my wallet at the restaurant","I lost my wallet in the subway","I lost my wallet and had to cancel my cards"],"example_sentence":"I lost my wallet on the bus.","example_es":"He perdido mi cartera en el autobús.","example_en":"I lost my wallet on the bus.","mnemonic_en":null},{"spanish_text":"Estoy enfermo","english_text":"I am sick","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"I am ill or unwell.","main_translations_es":["Me siento enfermo","Estoy indispuesto","Tengo fiebre"],"collocations":["I am sick with a cold","I am sick and need to rest","I am sick to my stomach","I am sick of this"],"example_sentence":"I am sick and can''t go to work.","example_es":"Estoy enfermo y no puedo ir al trabajo.","example_en":"I am sick and can''t go to work.","mnemonic_en":null},{"spanish_text":"Está roto","english_text":"It is broken","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"It is not functioning properly; it has been damaged.","main_translations_es":["Se ha roto","Se rompió","Está averiado"],"collocations":["It is broken beyond repair","It is broken into pieces","It is broken down","It is broken up"],"example_sentence":"The glass is broken.","example_es":"El vaso está roto.","example_en":"The glass is broken.","mnemonic_en":null},{"spanish_text":"No funciona","english_text":"It does not work","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A phrase indicating that something is not functioning or operating as intended.","main_translations_es":["No funciona"],"collocations":["It does not work for me","It does not work on my machine","It does not work as expected","It does not work properly"],"example_sentence":"The button I tried to press does not work.","example_es":"No funciona el botón que intenté presionar.","example_en":"The button I tried to press does not work.","mnemonic_en":null},{"spanish_text":"¿Puede repetir?","english_text":"Can you repeat?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A polite request asking someone to say something again.","main_translations_es":["¿Puedes repetir?","¿Podría repetir?","¿Me lo puede repetir?"],"collocations":["Can you repeat that?","Can you repeat the last part?","Can you repeat the instructions?","Can you repeat the question?"],"example_sentence":"Can you repeat what you said?","example_es":"¿Puede repetir lo que dijo?","example_en":"Can you repeat what you said?","mnemonic_en":null},{"spanish_text":"Más despacio, por favor","english_text":"More slowly, please","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A polite request to reduce the speed.","main_translations_es":["Más lento, por favor","Con más lentitud, por favor","Más pausado, por favor"],"collocations":["Could you speak more slowly, please?","Please speak more slowly, please.","Could you explain more slowly, please?"],"example_sentence":"Could you speak more slowly, please?","example_es":"Podrías hablar más despacio, por favor?","example_en":"Could you speak more slowly, please?","mnemonic_en":null},{"spanish_text":"No entiendo","english_text":"I do not understand","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement indicating lack of comprehension.","main_translations_es":["No comprendo","No lo entiendo","No me queda claro"],"collocations":["I do not understand what you mean","I do not understand the instructions","I do not understand why","I do not understand the concept"],"example_sentence":"I do not understand what you are saying.","example_es":"No entiendo lo que dices.","example_en":"I do not understand what you are saying.","mnemonic_en":null},{"spanish_text":"¿Habla inglés?","english_text":"Do you speak English?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking whether someone can speak English.","main_translations_es":["¿Hablas inglés?","¿Puede hablar inglés?","¿Puedes hablar inglés?"],"collocations":["speak English fluently","speak English well","speak English with confidence"],"example_sentence":"Do you speak English?","example_es":"¿Habla inglés?","example_en":"Do you speak English?","mnemonic_en":null},{"spanish_text":"¿Dónde puedo comprar agua?","english_text":"Where can I buy water?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking for the location where water can be purchased.","main_translations_es":["¿Dónde puedo comprar agua?","¿Dónde puedo conseguir agua?","¿Dónde puedo adquirir agua?"],"collocations":["Where can I buy water?","Where can I buy water in the city?","Where can I buy water near me?","Where can I buy water at the store?"],"example_sentence":"Where can I buy water?","example_es":"¿Dónde puedo comprar agua?","example_en":"Where can I buy water?","mnemonic_en":null},{"spanish_text":"¿Cuánto tarda?","english_text":"How long does it take?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking for the duration of an event or process.","main_translations_es":["¿Cuánto tiempo tarda?","¿Cuánto tiempo lleva?","¿Cuánto demora?"],"collocations":["How long does it take to finish?","How long does it take to get there?","How long does it take to learn?"],"example_sentence":"How long does it take?","example_es":"¿Cuánto tarda?","example_en":"How long does it take?","mnemonic_en":null},{"spanish_text":"¿A qué hora sale?","english_text":"What time does it leave?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking for the time at which something departs.","main_translations_es":["¿A qué hora parte?","¿A qué hora sale el tren?","¿A qué hora sale el autobús?"],"collocations":["I need to know what time does it leave?","Do you know what time does it leave?","Can you tell me what time does it leave?"],"example_sentence":"What time does the train leave?","example_es":"¿A qué hora sale el tren?","example_en":"What time does the train leave?","mnemonic_en":null},{"spanish_text":"¿A qué hora llega?","english_text":"What time does it arrive?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking for the time of arrival.","main_translations_es":["¿A qué hora llega?","¿Cuándo llega?"],"collocations":["What time does it arrive?","What time does it arrive at the station?","What time does it arrive on schedule?"],"example_sentence":"What time does the train arrive?","example_es":"¿A qué hora llega el tren?","example_en":"What time does the train arrive?","mnemonic_en":null},{"spanish_text":"¿Hay un baño?","english_text":"Is there a bathroom?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking whether a bathroom is available.","main_translations_es":["¿Dónde está el baño?","¿Hay un baño cerca?","¿Hay un baño en este lugar?"],"collocations":["Is there a bathroom nearby?","Is there a bathroom in this building?","Is there a bathroom on the second floor?","Is there a bathroom in the restaurant?"],"example_sentence":"Is there a bathroom nearby?","example_es":"¿Hay un baño cerca de aquí?","example_en":"Is there a bathroom nearby?","mnemonic_en":null},{"spanish_text":"¿Puedo pagar con tarjeta?","english_text":"Can I pay by card?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking if card payment is accepted.","main_translations_es":["¿Se puede pagar con tarjeta?","¿Puedo usar tarjeta para pagar?","¿Puedo pagar con mi tarjeta?"],"collocations":["pay by card","pay with card","pay using a card"],"example_sentence":"Can I pay by card?","example_es":"¿Puedo pagar con tarjeta?","example_en":"Can I pay by card?","mnemonic_en":null},{"spanish_text":"¿Tiene una habitación libre?","english_text":"Do you have a room available?","section_name":"Travel Phrases","part_of_speech":"question","definition_en":"A question asking whether a room is free for use.","main_translations_es":["¿Hay habitaciones disponibles?","¿Tiene habitaciones libres?","¿Tiene alguna habitación libre?"],"collocations":["Do you have a room available for tonight?","Do you have a room available for a short stay?","Do you have a room available for a conference?","Do you have a room available next week?"],"example_sentence":"Do you have a room available at your hotel?","example_es":"¿Tiene una habitación libre en su hotel?","example_en":"Do you have a room available at your hotel?","mnemonic_en":null},{"spanish_text":"Necesito una reserva","english_text":"I need a reservation","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"A statement indicating that the speaker requires a booking.","main_translations_es":["Quiero hacer una reserva","Necesito reservar","Me gustaría reservar"],"collocations":["I need a reservation for two","I need a reservation at 7pm","I need a reservation for tonight","I need a reservation for a table"],"example_sentence":"I need a reservation for dinner tomorrow.","example_es":"Necesito una reserva para cenar mañana.","example_en":"I need a reservation for dinner tomorrow.","mnemonic_en":null},{"spanish_text":"Estoy de vacaciones","english_text":"I am on vacation","section_name":"Travel Phrases","part_of_speech":"expression","definition_en":"I am currently away from work or home for leisure.","main_translations_es":["Estoy de vacaciones","Estoy de descanso"],"collocations":["on vacation","on a vacation","vacation mode","vacation days"],"example_sentence":"I am on vacation at the beach.","example_es":"Estoy de vacaciones en la playa.","example_en":"I am on vacation at the beach.","mnemonic_en":null},{"spanish_text":"Viaje de trabajo","english_text":"Business trip","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A trip taken for work purposes.","main_translations_es":["Viaje de negocios","Viaje corporativo"],"collocations":["short business trip","long business trip","business trip expenses","business trip itinerary"],"example_sentence":"I have to pack for the business trip tomorrow.","example_es":"Tengo que preparar mi equipaje para el viaje de trabajo mañana.","example_en":"I have to pack for the business trip tomorrow.","mnemonic_en":null},{"spanish_text":"Mal tiempo","english_text":"Bad weather","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"Unfavorable atmospheric conditions.","main_translations_es":["Mal tiempo","Mal clima"],"collocations":["bad weather","bad weather forecast","bad weather conditions","bad weather days"],"example_sentence":"The bad weather prevented us from going to the beach.","example_es":"El mal tiempo nos impidió salir a la playa.","example_en":"The bad weather prevented us from going to the beach.","mnemonic_en":null},{"spanish_text":"Soleado","english_text":"Sunny","section_name":"Travel Phrases","part_of_speech":"adjective","definition_en":"Having or showing a bright, warm, and clear sky.","main_translations_es":["soleado","brillante","radiante"],"collocations":["sunny day","sunny weather","sunny outlook","sunny disposition"],"example_sentence":"The day is sunny and perfect for a picnic.","example_es":"El día está soleado y perfecto para un picnic.","example_en":"The day is sunny and perfect for a picnic.","mnemonic_en":null},{"spanish_text":"Lluvioso","english_text":"Rainy","section_name":"Travel Phrases","part_of_speech":"adjective","definition_en":"characterized by frequent rain","main_translations_es":["humedecido","mojado","lluvioso"],"collocations":["rainy day","rainy season","rainy weather","rainy forecast"],"example_sentence":"The day is rainy.","example_es":"El día está lluvioso.","example_en":"The day is rainy.","mnemonic_en":null},{"spanish_text":"Ferry","english_text":"Ferry","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A boat or ship used to carry people or goods across a body of water.","main_translations_es":["ferry","transbordador","barco de ferry"],"collocations":["ferry crossing","ferry service","ferry terminal","ferry ride"],"example_sentence":"The ferry arrives at 10 in the morning.","example_es":"El ferry llega a las 10 de la mañana.","example_en":"The ferry arrives at 10 in the morning.","mnemonic_en":null},{"spanish_text":"Barco","english_text":"Boat","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A small vessel used for traveling on water.","main_translations_es":["Nave","Embarcación","Barcaza"],"collocations":["boat trip","boat ride","boat launch"],"example_sentence":"The boat sails calmly across the sea.","example_es":"El barco navega tranquilamente por el mar.","example_en":"The boat sails calmly across the sea.","mnemonic_en":null},{"spanish_text":"Playa","english_text":"Beach","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A sandy area by the sea where people can swim and sunbathe.","main_translations_es":["Costa","Litoral","Ribera"],"collocations":["beach house","beach day","beach front","beach volleyball"],"example_sentence":"I love walking along the beach at sunset.","example_es":"Me encanta caminar por la playa al atardecer.","example_en":"I love walking along the beach at sunset.","mnemonic_en":null},{"spanish_text":"Montaña","english_text":"Mountain","section_name":"Travel Phrases","part_of_speech":"noun","definition_en":"A large natural elevation of the earth''s surface, typically rising abruptly and reaching a peak.","main_translations_es":["pico","cerro","montañón"],"collocations":["mountain range","mountain peak","mountain trail","mountain view"],"example_sentence":"The mountain rises majestically over the valley.","example_es":"La montaña se alza majestuosa sobre el valle.","example_en":"The mountain rises majestically over the valley.","mnemonic_en":null}]'::jsonb) as x(
  spanish_text text, english_text text, section_name text, part_of_speech text, definition_en text,
  main_translations_es jsonb, collocations jsonb, example_sentence text, example_es text, example_en text, mnemonic_en text
)
where not exists (
  select 1 from public.cards c2
  where c2.deck_id = dk.id
    and lower(c2.spanish_text) = lower(x.spanish_text)
    and lower(c2.english_text) = lower(x.english_text)
);

-- ai-batch-cafe-basics (100 cards)
insert into public.decks (slug, title, description, language_from, language_to)
values ('ai-batch-cafe-basics', 'Cafe Counter Basics', 'Short English needed for simple cafe orders.', 'es', 'en')
on conflict (slug) do nothing;

insert into public.cards (deck_id, spanish_text, english_text, is_enabled, generation_phase, generation_metadata, section_name, part_of_speech, definition_en, main_translations_es, collocations, example_sentence, example_es, example_en, mnemonic_en)
select dk.id, x.spanish_text, x.english_text, true, 'refined', '{}'::jsonb, x.section_name, x.part_of_speech, x.definition_en,
       coalesce(x.main_translations_es, '[]'::jsonb), coalesce(x.collocations, '[]'::jsonb), x.example_sentence, x.example_es, x.example_en, x.mnemonic_en
from (select id from public.decks where slug = 'ai-batch-cafe-basics') dk
