ations_es":["servilleta de papel","pañuelo","toalla de mesa"],"collocations":["paper napkin","napkin ring","wet napkin","napkin holder"],"example_sentence":"Please pass me the napkin to clean the table.","example_es":"Por favor, pásame la servilleta para limpiar la mesa.","example_en":"Please pass me the napkin to clean the table.","mnemonic_en":null},{"spanish_text":"Taza","english_text":"Cup","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A small, open container, typically with a handle, used for drinking liquids.","main_translations_es":["taza","copa","tazón"],"collocations":["cup of tea","cup of coffee","cup of water","cup of sugar"],"example_sentence":"I''m going to buy a new cup for my coffee.","example_es":"Voy a comprar una taza nueva para mi café.","example_en":"I''m going to buy a new cup for my coffee.","mnemonic_en":null},{"spanish_text":"Vaso","english_text":"Glass","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A hard, transparent material used for windows, bottles, and other objects.","main_translations_es":["vaso","copa","copa de vino"],"collocations":["glass of water","glass ceiling","glass jar","glass bottle"],"example_sentence":"Put the glass on the table.","example_es":"Pon el vaso sobre la mesa.","example_en":"Put the glass on the table.","mnemonic_en":null},{"spanish_text":"Plato","english_text":"Plate","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A flat dish used for serving or eating food.","main_translations_es":["plato","cazuela","plato hondo"],"collocations":["plate of food","clean your plate","plate tectonics"],"example_sentence":"I placed the plate on the table.","example_es":"Puse el plato sobre la mesa.","example_en":"I placed the plate on the table.","mnemonic_en":null},{"spanish_text":"Cuchara","english_text":"Spoon","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A utensil with a shallow bowl and a handle used for scooping, stirring, or serving food.","main_translations_es":["cucharita","cucharilla","cuchara de té"],"collocations":["spoonful of sugar","spoon feeding","spoon and fork","spoon in the drawer"],"example_sentence":"I need a spoon to stir the soup.","example_es":"Necesito una cuchara para mezclar la sopa.","example_en":"I need a spoon to stir the soup.","mnemonic_en":null},{"spanish_text":"Tenedor","english_text":"Fork","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A utensil with two or more prongs used for eating or serving food.","main_translations_es":["tenedor","tenedor de mesa","tenedor de cocina"],"collocations":["fork in the road","fork out","fork over","forklift"],"example_sentence":"Can you pass me the fork, please?","example_es":"¿Puedes pasarme el tenedor, por favor?","example_en":"Can you pass me the fork, please?","mnemonic_en":null},{"spanish_text":"Cuchillo","english_text":"Knife","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A cutting instrument with a blade and handle used for slicing, cutting, or stabbing.","main_translations_es":["cuchilla","navaja","cuchillo de cocina"],"collocations":["knife and fork","knife edge","knife block","knife skills"],"example_sentence":"I need a knife to cut the bread.","example_es":"Necesito un cuchillo para cortar el pan.","example_en":"I need a knife to cut the bread.","mnemonic_en":null},{"spanish_text":"Bandeja","english_text":"Tray","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A flat, shallow container used for holding or carrying items.","main_translations_es":["charola","plato","cesta"],"collocations":["serving tray","tray of cookies","tray table","tray line"],"example_sentence":"I placed the food on the tray.","example_es":"Puse la comida en la bandeja.","example_en":"I placed the food on the tray.","mnemonic_en":null},{"spanish_text":"Mesa","english_text":"Table","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A piece of furniture with a flat top and legs, used for working, eating, or placing items.","main_translations_es":["mesa","mesa de comedor","mesa de escritorio"],"collocations":["dinner table","table of contents","round table","table tennis"],"example_sentence":"I placed the book on the table.","example_es":"Puse el libro sobre la mesa.","example_en":"I placed the book on the table.","mnemonic_en":null},{"spanish_text":"Silla","english_text":"Chair","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A piece of furniture with a seat, back, and legs, used for sitting.","main_translations_es":["butaca","asiento","sillón"],"collocations":["chair the meeting","chair of the board","rocking chair","chairperson"],"example_sentence":"The chair is next to the table.","example_es":"La silla está junto a la mesa.","example_en":"The chair is next to the table.","mnemonic_en":null},{"spanish_text":"Menú","english_text":"Menu","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A list of dishes offered by a restaurant or a set of selectable options in a software program.","main_translations_es":["Carta","Lista de platos","Selección"],"collocations":["menu options","menu board","menu item","menu planning"],"example_sentence":"Can you pass me the menu, please?","example_es":"¿Puedes pasarme el menú, por favor?","example_en":"Can you pass me the menu, please?","mnemonic_en":null},{"spanish_text":"Mostrador","english_text":"Counter","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"A flat surface in a shop, restaurant, or bank where transactions are conducted.","main_translations_es":["mostrador","barra","taquilla"],"collocations":["counter offer","counter strike","counter argument","counter top"],"example_sentence":"I left my bag on the store counter.","example_es":"Dejé mi bolso en el mostrador de la tienda.","example_en":"I left my bag on the store counter.","mnemonic_en":null},{"spanish_text":"Terraza","english_text":"Patio","section_name":"Cafe Counter Basics","part_of_speech":"noun","definition_en":"An outdoor space adjoining a building, often paved and used for dining or recreation.","main_translations_es":["azotea","balcón"],"collocations":["patio furniture","patio door","patio garden"],"example_sentence":"We sat on the patio to have coffee.","example_es":"Nos sentamos en la terraza a tomar el café.","example_en":"We sat on the patio to have coffee.","mnemonic_en":null},{"spanish_text":"Para llevar","english_text":"To go","section_name":"Cafe Counter Basics","part_of_speech":"verb","definition_en":"To order food or drink to be taken away and consumed elsewhere.","main_translations_es":["para llevar","para llevar a casa","para llevar fuera"],"collocations":["to go out","to go ahead","to go for","to go on"],"example_sentence":"I want the sandwich to go.","example_es":"Quiero el sándwich para llevar.","example_en":"I want the sandwich to go.","mnemonic_en":null},{"spanish_text":"Para aquí","english_text":"For here","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"Used to indicate that something should be placed or remain at this location.","main_translations_es":["para consumir aquí","para comer aquí","para quedarse aquí"],"collocations":["Is that for here or to go?","I''ll have it for here.","Do you want it for here?","Can I get that for here?"],"example_sentence":"For here or to go?","example_es":"¿Para aquí o para llevar?","example_en":"For here or to go?","mnemonic_en":null},{"spanish_text":"Quiero pedir","english_text":"I want to order","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A statement expressing a desire to place an order.","main_translations_es":["Me gustaría pedir","Deseo pedir","Quisiera pedir"],"collocations":["I want to order a pizza","I want to order online","I want to order now","I want to order something"],"example_sentence":"I want to order a pizza for dinner.","example_es":"Quiero pedir una pizza para la cena.","example_en":"I want to order a pizza for dinner.","mnemonic_en":null},{"spanish_text":"Quisiera un...","english_text":"I would like a...","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"A polite way to say that you want something.","main_translations_es":["Me gustaría un...","Desearía un...","Quisiera un..."],"collocations":["I would like a coffee","I would like a drink","I would like a break","I would like a moment"],"example_sentence":"I would like a coffee, please.","example_es":"Quisiera un café, por favor.","example_en":"I would like a coffee, please.","mnemonic_en":null},{"spanish_text":"¿Qué recomienda?","english_text":"What do you recommend?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A polite request asking for a suggestion or advice.","main_translations_es":["¿Qué me recomiendas?","¿Qué sugieres?","¿Qué me aconsejas?"],"collocations":["What do you recommend for dinner?","What do you recommend we do?","What do you recommend we try?"],"example_sentence":"What do you recommend for dinner?","example_es":"¿Qué recomienda para la cena?","example_en":"What do you recommend for dinner?","mnemonic_en":null},{"spanish_text":"¿Qué lleva?","english_text":"What is in it?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A question asking about the contents of something.","main_translations_es":["¿Qué contiene?","¿Qué hay dentro?","¿Qué incluye?"],"collocations":["Can you tell me what is in it?","I wonder what is in it.","Do you know what is in it?","Let''s find out what is in it."],"example_sentence":"What is in it?","example_es":"¿Qué lleva la ensalada?","example_en":"What is in it?","mnemonic_en":null},{"spanish_text":"¿Tiene opciones vegetarianas?","english_text":"Do you have vegetarian options?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A polite inquiry asking whether vegetarian dishes are available.","main_translations_es":["¿Ofrecen opciones vegetarianas?","¿Hay opciones vegetarianas?","¿Tienen platos vegetarianos?"],"collocations":["Do you have vegetarian options on the menu?","Do you have vegetarian options available?","Do you have vegetarian options here?"],"example_sentence":"Do you have vegetarian options?","example_es":"¿Tiene opciones vegetarianas?","example_en":"Do you have vegetarian options?","mnemonic_en":null},{"spanish_text":"¿Tiene leche sin lactosa?","english_text":"Do you have lactose-free milk?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A polite inquiry asking if lactose-free milk is available.","main_translations_es":["¿Tiene leche sin lactosa?","¿Hay leche sin lactosa?","¿Dispone de leche sin lactosa?"],"collocations":["lactose-free milk options","order lactose-free milk","buy lactose-free milk","lactose-free milk is available"],"example_sentence":"Excuse me, do you have lactose-free milk?","example_es":"Disculpe, ¿tiene leche sin lactosa?","example_en":"Excuse me, do you have lactose-free milk?","mnemonic_en":null},{"spanish_text":"¿Sin azúcar?","english_text":"Without sugar?","section_name":"Cafe Counter Basics","part_of_speech":"question","definition_en":"A question asking whether something contains no sugar.","main_translations_es":["¿Sin azúcar añadido?","¿Libre de azúcar?","¿Sin azúcar?"],"collocations":["coffee without sugar","order it without sugar","ask for it without sugar","drink it without sugar"],"example_sentence":"\"Without sugar?\" the waiter asked.","example_es":"¿Sin azúcar? preguntó el camarero.","example_en":"\"Without sugar?\" the waiter asked.","mnemonic_en":null},{"spanish_text":"Con hielo","english_text":"With ice","section_name":"Cafe Counter Basics","part_of_speech":"expression","definition_en":"Indicates that something is served or prepared together with ice.","main_translations_es":["Con hielo","Con hielo incluido","Con hielo al servir"],"collocations":["served with ice","drink it with ice","on the rocks","mixed with ice"],"example_sentence":"I want my drink with ice.","example_es":"Quiero mi bebida con hielo.","example_en":"I want my drink with ice.","mnemonic_en":null},{"spanish_text":"Caliente","english_text":"Hot","section_name":"Cafe Counter Basics","part_of_speech":"adjective","definition_en":"Having a high temperature or feeling warmth.","main_translations_es":["Caluroso","Ardiente","Candente"],"collocations":["hot weather","hot coffee","hot topic","hot deal"],"example_sentence":"The coffee is hot.","example_es":"El café está caliente.","example_en":"The coffee is hot.","mnemonic_en":null},{"spanish_text":"Frío","english_text":"Cold","section_name":"Cafe Counter Basics","part_of_speech":"adjective","definition_en":"Having a low temperature; not warm.","main_translations_es":["Frío","Helado","Gélido"],"collocations":["cold weather","cold drink","cold shoulder","catch a cold"],"example_sentence":"It''s very cold today.","example_es":"Hace mucho frío hoy.","example_en":"It''s very cold today.","mnemonic_en":null},{"spanish_text":"Tibio","english_text":"Warm","section_name":"Cafe Counter Basics","part_of_speech":"adjective","definition_en":"Having a moderately high temperature that is comfortably heated, but not hot.","main_translations_es":["cálido","templado"],"collocations":["warm welcome","warm weather","warm feeling","warm up"],"example_sentence":"The coffee is warm, it''s neither cold nor hot.","example_es":"El café está tibio, no está ni frío ni caliente.","example_en":"The coffee is warm, it''s neither cold nor hot.","mnemonic_en":null},{"spanish_text":"Grande","english_text":"Large","section_name":"Cafe Counter Basics","part_of_speech":"adjective","definition_en":"Having a size that is greater than normal or expected.","main_translations_es":["Enorme","Gigante","Amplio"],"collocations":["large amount","large scale","large number","large size"],"example_sentence":